def gen(rng, size):
    n = 1 << rng.randint(0, 5)
    def make_grid():
        base = rng.randint(0, 1)
        g = [[base] * n for _ in range(n)]
        for _ in range(rng.randint(0, 5)):
            r1 = rng.randrange(n)
            r2 = rng.randint(r1, n - 1)
            c1 = rng.randrange(n)
            c2 = rng.randint(c1, n - 1)
            v = rng.randint(0, 1)
            for r in range(r1, r2 + 1):
                for c in range(c1, c2 + 1):
                    g[r][c] = v
        return g
    def to_wire(g):
        def build(r, c, s):
            v = g[r][c]
            if all(g[r + i][c + j] == v for i in range(s) for j in range(s)):
                return {'leaf': True, 'val': v, 'kids': None}
            h = s // 2
            return {'leaf': False, 'val': 1, 'kids': [
                build(r, c, h), build(r, c + h, h),
                build(r + h, c, h), build(r + h, c + h, h)]}
        root = build(0, 0, n)
        out = []
        queue = [root]
        while queue:
            node = queue.pop(0)
            if node is None:
                out.append(None)
                continue
            out.append([1 if node['leaf'] else 0, node['val']])
            if node['kids']:
                queue.extend(node['kids'])
            else:
                queue.extend([None, None, None, None])
        while out and out[-1] is None:
            out.pop()
        return out
    return [to_wire(make_grid()), to_wire(make_grid())]

