class Solution:
    def intersect(self, quadTree1: 'Node', quadTree2: 'Node') -> 'Node':
        def depth(node):
            if node.isLeaf:
                return 0
            return 1 + max(depth(node.topLeft), depth(node.topRight),
                           depth(node.bottomLeft), depth(node.bottomRight))
        d = max(depth(quadTree1), depth(quadTree2))
        n = 1 << d
        def fill(node, r, c, s, g):
            if node.isLeaf:
                v = 1 if node.val else 0
                for i in range(s):
                    for j in range(s):
                        g[r + i][c + j] = v
                return
            h = s // 2
            fill(node.topLeft, r, c, h, g)
            fill(node.topRight, r, c + h, h, g)
            fill(node.bottomLeft, r + h, c, h, g)
            fill(node.bottomRight, r + h, c + h, h, g)
        g1 = [[0] * n for _ in range(n)]
        g2 = [[0] * n for _ in range(n)]
        fill(quadTree1, 0, 0, n, g1)
        fill(quadTree2, 0, 0, n, g2)
        g = [[g1[i][j] | g2[i][j] for j in range(n)] for i in range(n)]
        def build(r, c, s):
            v = g[r][c]
            if all(g[r + i][c + j] == v for i in range(s) for j in range(s)):
                return Node(v == 1, True)
            h = s // 2
            return Node(True, False,
                        build(r, c, h), build(r, c + h, h),
                        build(r + h, c, h), build(r + h, c + h, h))
        return build(0, 0, n)

